type Role = "admin" | "user" | "guest";

// TypeScript loves this:
let myRole: Role = "admin";

// TypeScript immediately rejects this:
let badRole: Role = "superadmin"; // Error!

enum Direction {
  Up,
  Down,
  Left,
  Right
}

// We access it like a property
let myMove: Direction = Direction.Up;

// By default, TS assigns them numbers starting at 0
console.log(Direction.Up); // Outputs: 0
